import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    // Simulasi data yang lebih lengkap (Ganti dengan integrasi API Anda)
    const job = { 
        id: id, 
        title: 'Fullstack Developer', 
        company: 'PasukanYerusSolo', 
        location: 'Solo (Remote)', 
        salary: 'Rp 8.000.000 - Rp 12.000.000', 
        type: 'Full-time',
        postedAt: '2 hari yang lalu',
        desc: 'Kami mencari pengembang yang antusias untuk membangun arsitektur web modern...',
        requirements: [
            'Pengalaman minimal 2 tahun dengan React.js dan Laravel.',
            'Memahami RESTful API dan integrasi database.',
            'Bisa bekerja secara mandiri dalam lingkungan remote.',
            'Memiliki kemampuan problem solving yang baik.'
        ]
    };

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            {/* Navigasi Kembali */}
            <button 
                onClick={() => navigate(-1)} 
                style={{ background: 'none', border: 'none', color: '#a3a3a3', cursor: 'pointer', marginBottom: '20px' }}
            >
                ← Kembali ke Daftar Lowongan
            </button>

            <div style={{ padding: '40px', background: '#120b06', borderRadius: '16px', border: '1px solid #262626' }}>
                {/* Header Lowongan */}
                <h1 style={{ color: '#fef3c7', fontSize: '32px', marginBottom: '8px' }}>{job.title}</h1>
                <p style={{ color: '#ea580c', fontSize: '18px', fontWeight: 'bold' }}>{job.company}</p>
                <div style={{ display: 'flex', gap: '20px', margin: '15px 0', color: '#a3a3a3', fontSize: '14px' }}>
                    <span>📍 {job.location}</span>
                    <span>🕒 {job.type}</span>
                    <span>📅 {job.postedAt}</span>
                </div>

                {/* Deskripsi */}
                <div style={{ margin: '30px 0', padding: '20px 0', borderTop: '1px solid #262626' }}>
                    <h3 style={{ color: '#fef3c7' }}>Tentang Pekerjaan</h3>
                    <p style={{ color: '#a3a3a3', lineHeight: '1.8' }}>{job.desc}</p>
                </div>

                {/* Kualifikasi */}
                <div style={{ marginBottom: '30px' }}>
                    <h3 style={{ color: '#fef3c7' }}>Kualifikasi</h3>
                    <ul style={{ color: '#a3a3a3', lineHeight: '1.8', paddingLeft: '20px' }}>
                        {job.requirements.map((req, index) => (
                            <li key={index} style={{ marginBottom: '8px' }}>{req}</li>
                        ))}
                    </ul>
                </div>

                {/* Gaji & Aksi */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '30px', paddingTop: '20px', borderTop: '1px solid #262626' }}>
                    <div style={{ fontSize: '18px', fontWeight: 'bold', color: '#fef3c7' }}>
                        Gaji: {job.salary}
                    </div>
                    <button style={{ padding: '14px 32px', background: '#ea580c', color: '#fff', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' }}>
                        Lamar Sekarang
                    </button>
                </div>
            </div>
        </div>
    );
};

export default JobDetail;
